            void setRoutingAllowed(bool value) { allowRouting = value ? allowRoutingTrue : allowRoutingFalse; }
            void unsetRoutingAllowed() { allowRouting = allowRoutingNone; }
            void setPostOnly(bool value) { postOnly = value; }
            void setIso(bool value) { iso = value; }
            void setAllOrNone(bool value) { allOrNone = value; }
            void setArcaTracking(bool value) { arcaTracking = value; }
            void setIseExposureFlag(const std::string& value) { iseExposureFlag = value; }
            void setIseDisplayWhen(char value) { iseDisplayWhen = value; }
            void setIseDisplayRange(int value) { iseDisplayRange = value; }
            void setCustomerType(CustomerType type) { customerType = type; }
            void setClientData1(const std::string& value) { clientData1 = value; }
            void setClientData2(const std::string& value) { clientData2 = value; }
            void setClientData3(const std::string& value) { clientData3 = value; }

