            uint64_t endTime;                   // Time specified in UTC as milliseconds since Epoch for the end of strategy execution
            ScaledPrice iWouldPx;               // Price at which to trigger market specific behavior
            bool saleAffirm;                    // Should be set for each long or short sale order by clients who trade away from Lime to represent
                                                      // that the client owns the security being sold or will own it by settlement time.
            int shortSaleAffirmLongQuantity;    // This option should be used to indicate the long portion of the short sale when using sale affirmation.
            bool invisible;                     // Enabling this option will result in a hidden order
