        // Place new US Equities/Futures order with specified parameters.
        CallStatus placeOrder(
            OrderId orderId,
            const std::string& symbol,
            int quantity,
            ScaledPrice price,
            Side side,
            const std::string& route,
            const OrderProperties& properties = nullProperties);

        // Place new US Equities/Futures order with specified parameters.
        CallStatus placeOrder(
            OrderId orderId,
            const std::string& route,
            const std::string& symbol,
            Side side,
            int quantity,
            ScaledPrice price = marketPrice,
            const OrderProperties& properties = nullProperties);

        // Place new US Options order with specified parameters.
        CallStatus placeUSOptionsOrder(
            OrderId orderId,
            const std::string& route,
            const USOptionSymbol& symbol,
            Side side,
            PositionEffect positionEffect,
            int quantity,
            ScaledPrice price = marketPrice,
            const USOptionsOrderProperties& properties = nullUSOptionsProperties);

        // Place new US Equities Algo order with specified parameters.
        CallStatus placeAlgoOrder(
            OrderId orderId,
            const std::string& route,
            const std::string& symbol,
            Side side,
            int quantity,
            const std::string& strategy,
            ScaledPrice price = marketPrice,
            const AlgoOrderProperties& properties = nullAlgoProperties);

